                user_id: r.userId,
                version: r.version,
                permission_read: r.permissionRead,
                permission_write: r.permissionWrite,
                create_time: new Date((r.createTime || 0) * 1000).toISOString(),
                update_time: new Date((r.updateTime || 0) * 1000).toISOString(),
                value: r.value
